/**
 * Streaming JSON Parser Utility
 * Implements stream-json strategy for handling massive JSON files
 * without heap overflow on lower-memory devices (Raspberry Pi, Termux)
 */

import { createReadStream, statSync, readFileSync } from 'fs';
import { readFromInput } from './input.js';
import type { ProjectSnapshot, SnapshotMetadata } from '../types/index.js';
import parser from 'stream-json/parser.js';
import streamObject from 'stream-json/streamers/stream-object.js';
import pick from 'stream-json/filters/pick.js';
import chain from 'stream-chain';

const MAX_BUFFER_SIZE = 8 * 1024 * 1024; // 8MB max buffer before streaming parse

/**
 * Parse JSON from string input with size check
 * Uses native JSON.parse for smaller files, streaming for larger ones
 */
export async function parseJSON(input: string): Promise<ProjectSnapshot> {
  const size = Buffer.byteLength(input, 'utf8');

  if (size < MAX_BUFFER_SIZE) {
    return JSON.parse(input) as ProjectSnapshot;
  }

  // Fallback to building the object if we MUST return ProjectSnapshot
  // but it's dangerous for large files
  return new Promise((resolve, reject) => {
    const snapshot: any = { files: {} };
    const pipeline = chain([
      Readable.from([input]),
      parser(),
      streamObject()
    ]);

    pipeline.on('data', (data) => {
      if (data.key === 'files') {
          // This still builds the files object, we need a better way
          snapshot.files = data.value;
      } else {
          snapshot[data.key] = data.value;
      }
    });

    pipeline.on('end', () => resolve(snapshot as ProjectSnapshot));
    pipeline.on('error', reject);
  });
}

import { Readable } from 'stream';

/**
 * Streaming process for snapshots of any size (up to 1GB+)
 * Dispatches metadata and files to callbacks to maintain low memory usage
 */
export async function processSnapshot(
  input: string | NodeJS.ReadableStream,
  callbacks: {
    onMetadata?: (key: string, value: any) => void;
    onFile?: (path: string, content: string) => Promise<void> | void;
  }
): Promise<void> {
  return new Promise((resolve, reject) => {
    const inputStream = typeof input === 'string' ? Readable.from([input]) : input;

    // Use a custom pipeline to handle the nested "files" object
    const p = parser();
    inputStream.pipe(p);

    let inFiles = false;
    let filesLevel = 0;

    p.on('data', async (data) => {
      try {
        if (data.name === 'startObject' && data.key === 'files') {
          inFiles = true;
          filesLevel = 0;
          return;
        }

        if (inFiles) {
          if (data.name === 'startObject') filesLevel++;
          if (data.name === 'endObject') {
            if (filesLevel === 0) {
              inFiles = false;
            } else {
              filesLevel--;
            }
            return;
          }

          if (filesLevel === 0 && data.name === 'stringValue' && callbacks.onFile) {
            await callbacks.onFile(data.key, data.value);
          }
        } else if (data.name === 'stringValue' || data.name === 'numberValue' || data.name === 'booleanValue' || data.name === 'nullValue') {
          if (callbacks.onMetadata) {
            callbacks.onMetadata(data.key, data.value);
          }
        }
      } catch (err) {
        reject(err);
      }
    });

    p.on('end', () => resolve());
    p.on('error', reject);
  });
}

/**
 * Load snapshot from file path with streaming support
 */
export async function loadSnapshotFromFile(filePath: string): Promise<ProjectSnapshot> {
  const stats = statSync(filePath);

  if (stats.size > MAX_BUFFER_SIZE) {
    // If it's too large, we should probably warn, but for now we'll try to load it
    // Commands should be updated to use processSnapshot instead
  }

  const content = readFileSync(filePath, 'utf8');
  return JSON.parse(content) as ProjectSnapshot;
}

/**
 * Load snapshot from stdin or string input
 */
export async function loadSnapshot(input?: string): Promise<ProjectSnapshot> {
  let data: string;

  if (input) {
    data = input;
  } else {
    data = await readFromInput();
  }

  if (!data.trim()) {
    throw new Error('No input provided');
  }

  return parseJSON(data);
}

/**
 * Calculate metadata from snapshot
 */
export function calculateMetadata(snapshot: ProjectSnapshot): SnapshotMetadata {
  const fileCount = Object.keys(snapshot.files).length;
  let totalSize = 0;

  for (const content of Object.values(snapshot.files)) {
    totalSize += Buffer.byteLength(content, 'utf8');
  }

  return {
    fileCount,
    totalSize,
    hasInstruction: Boolean(snapshot.instruction),
    hasFileSummary: Boolean(snapshot.fileSummary),
    hasUserProvidedHeader: Boolean(snapshot.userProvidedHeader),
    directoryStructureLines: snapshot.directoryStructure
      ? snapshot.directoryStructure.split('\n').length
      : 0
  };
}

