        const parsed = JSON.parse(data) as ProjectSnapshot;
        resolve(parsed);
      } catch (err) {
        reject(new Error(`Failed to parse JSON: ${(err as Error).message}`));
      }
    });

    stream.on('error', (err) => {
      reject(err);
    });
  });
