      if (!existsSync(parentDir)) {
        await mkdirAsync(parentDir, { recursive: true });
      }

      // Write file
      await writeFileAsync(outputPath, content, 'utf8');

      return {
        path: outputPath,
        size: Buffer.byteLength(content, 'utf8'),
