                p.pause();
                result.then(() => {
                  pendingOps--;
                  p.resume();
                  checkFinished();
                }).catch((err) => {
                  p.destroy(err);
                });
              }
            }
            currentFileKey = null;
          } else if (!inFiles && currentKey) {
            if (callbacks.onMetadata) {
              callbacks.onMetadata(currentKey, data.value);
            }
            currentKey = null;
          }
        }
      } catch (err) {
        p.destroy(err as Error);
      }
    });

    p.on('end', () => {
      finished = true;
      checkFinished();
    });

    p.on('error', reject);
