import { Command, type CommandDefinition } from '../utils/command.js';
import type { CLIOptions, CommandResult, CommandContext, ProjectSnapshot } from '../types/index.js';
import { join, relative, basename } from 'path';
import { readFileSync, existsSync, lstatSync, readdirSync } from 'fs';
import { execSync } from 'child_process';
import ignore from 'ignore';

export class PackCommand extends Command {
  readonly definition: CommandDefinition = {
    name: 'pack',
    description: 'Create a snapshot from a local directory',
    usage: 'jref pack [directory] [options]',
    examples: [
      'jref pack . > snapshot.json',
      'jref pack ./my-project --instruction "Follow these rules" > snapshot.json'
    ]
  };

  async execute(
    args: string[],
    options: CLIOptions,
    _context: CommandContext
  ): Promise<CommandResult> {
    try {
      const { flags, targetDir } = this.parseArgs(args);
      const rootDir = targetDir || process.cwd();

      if (!existsSync(rootDir)) {
        return this.error(`Directory not found: ${rootDir}`, options);
      }

      // Try to use repomix CLI first
      try {
        const snapshot = await this.packWithRepomixCLI(rootDir, flags);
        const output = JSON.stringify(snapshot, null, 2);

        // If --json flag is set or silent, we don't print decoration
        if (options.json || options.silent) {
          return this.success(output);
        }

        console.log(output);
        return this.success(output);
      } catch (repomixError) {
        // If repomix fails, fall back to original implementation
        console.warn('Repomix packing failed, falling back to native implementation:', (repomixError as Error).message);
        return this.fallbackPack(rootDir, flags, options);
      }

    } catch (err) {
      return this.error(`Pack failed: ${(err as Error).message}`, options);
    }
  }

  private async packWithRepomixCLI(rootDir: string, flags: Record<string, unknown>): Promise<ProjectSnapshot> {
    // Build repomix command arguments
    const args = [
      '--style', 'json',
      '--stdout',
      '--no-git-sort-by-changes', // We want to preserve file order like jref does
      '--remove-comments', 'false',
      '--remove-empty-lines', 'false',
      '--truncate-base64', 'false',
      '--output-show-line-numbers', 'false',
      '--no-copy', // Don't copy to clipboard
      '--include-empty-directories', 'true',
      '--include-full-directory-structure', 'true',
      '--no-security-check', // Disable security check to match jref's behavior
    ];

    // Add --summary flag if provided
    if (flags.summary !== undefined) {
      args.push('--file-summary');
      args.push('true');
    } else {
      args.push('--no-file-summary');
    }

    // Add instruction if provided
    if (flags.instruction) {
      args.push('--instruction-file-path');
      // We'll create a temporary file for the instruction
      // For simplicity, we'll handle instruction separately after getting repomix output
    }

    // Add the directory to pack
    args.push(rootDir);

    try {
      // Run repomix CLI and capture output
      const output = execSync(
        `node ./node_modules/repomix/bin/repomix.cjs ${args.map(arg => `'${arg}'`).join(' ')}`,
        { encoding: 'utf8', maxBuffer: 1024 * 1024 * 10 } // 10MB buffer
      );

      // Parse the JSON output
      let snapshotData: any = {};
      try {
        snapshotData = JSON.parse(output);
      } catch (e) {
        throw new Error(`Failed to parse repomix JSON output: ${(e as Error).message}`);
      }

      // Convert repomix output to jref snapshot format
      const snapshot: ProjectSnapshot = {
        directoryStructure: this.formatDirectoryStructure(
          snapshotData.directoryStructure || '',
          basename(rootDir)
        ),
        files: snapshotData.files || {},
        instruction: flags.instruction as string || undefined,
        fileSummary: flags.summary as string || undefined
      };

      return snapshot;
    } catch (err) {
      // If repomix CLI fails, throw error to trigger fallback
      throw new Error(`Repomix CLI execution failed: ${(err as Error).message}`);
    }
  }

  private formatDirectoryStructure(repomixTree: string, rootDirName: string): string {
    // Repomix produces a tree like: "main.ts\npackage.json"
    // We need to convert it to: "rootDirName/\n├── main.ts\n└── package.json"

    if (!repomixTree || !repomixTree.trim()) {
      return `${rootDirName}/`;
    }

    const lines = repomixTree.split('\n').filter(line => line.trim());
    if (lines.length === 0) {
      return `${rootDirName}/`;
    }

    // If there's only one item, we still need to show it properly
    const treeLines = [`${rootDirName}/`];

    for (let i = 0; i < lines.length; i++) {
      const isLast = i === lines.length - 1;
      const line = lines[i].trim();
      // Clean up any extra characters repomix might add
      const cleanLine = line.replace(/^[├└│\s]+/, '');
      treeLines.push(`${isLast ? '└── ' : '├── '}${cleanLine}`);
    }

    return treeLines.join('\n');
  }

  private fallbackPack(rootDir: string, flags: Record<string, unknown>, options: CLIOptions): CommandResult {
    // Original implementation as fallback
    try {
      const files: Record<string, string> = {};
      const ig = ignore();

      // Load .gitignore if it exists
      const gitignorePath = join(rootDir, '.gitignore');
      if (existsSync(gitignorePath)) {
        ig.add(readFileSync(gitignorePath, 'utf8'));
      }

      // Always ignore .git
      ig.add('.git');

      const treeLines: string[] = [basename(rootDir) + '/'];
      this.walk(rootDir, rootDir, ig, files, treeLines, '');

      const snapshot: ProjectSnapshot = {
        directoryStructure: treeLines.join('\n'),
        files,
        instruction: (flags.instruction as string) || undefined,
        fileSummary: (flags.summary as string) || undefined
      };

      const output = JSON.stringify(snapshot, null, 2);

      // If --json flag is set or silent, we don't print decoration
      if (options.json || options.silent) {
        return this.success(output);
      }

      console.log(output);
      return this.success(output);
    } catch (err) {
      return this.error(`Pack failed: ${(err as Error).message}`, options);
    }
  }

  private walk(
    currentDir: string,
    rootDir: string,
    ig: any,
    files: Record<string, string>,
    treeLines: string[],
    prefix: string
  ): void {
    const entries = readdirSync(currentDir).sort();

    entries.forEach((entry, index) => {
      const fullPath = join(currentDir, entry);
      const relPath = relative(rootDir, fullPath);

      if (ig.ignores(relPath)) return;

      const isLast = index === entries.length - 1;
      const stats = lstatSync(fullPath);
      const isDir = stats.isDirectory();

      // Add to tree
      treeLines.push(`${prefix}${isLast ? '└── ' : '├── '}${entry}${isDir ? '/' : ''}`);

      if (isDir) {
        this.walk(fullPath, rootDir, ig, files, treeLines, prefix + (isLast ? '    ' : '│   '));
      } else {
        files[relPath] = readFileSync(fullPath, 'utf8');
      }
    });
  }

  protected parseArgs(args: string[]): { flags: Record<string, unknown>; targetDir?: string } {
    const flags: Record<string, unknown> = {};
    let targetDir: string | undefined;

    for (let i = 0; i < args.length; i++) {
      const arg = args[i];
      if (arg === '--instruction') {
        flags.instruction = args[++i];
      } else if (arg === '--summary') {
        flags.summary = args[++i];
      } else if (!arg.startsWith('-')) {
        targetDir = arg;
      }
    }

    return { flags, targetDir };
  }
}

